<!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><title>{{ $invoice->invoice_number }}</title><style>body{font-family:DejaVu Sans, sans-serif;direction:rtl}.wrap{max-width:900px;margin:auto}.head{display:flex;justify-content:space-between;border-bottom:2px solid #111;margin-bottom:20px}.table{width:100%;border-collapse:collapse}.table th,.table td{border:1px solid #999;padding:8px}.totals{width:320px;margin-right:auto;margin-top:20px}</style></head><body><div class="wrap"><div class="head"><div><h1>فاتورة داخلية</h1><p>{{ $invoice->invoice_number }}</p></div><div><p>{{ $invoice->company?->legal_name_ar }}</p><p>{{ $invoice->issue_date?->format('Y-m-d') }}</p></div></div><p><strong>العميل/المورد:</strong> {{ $invoice->contact?->name_ar }}</p><table class="table"><tr><th>الوصف</th><th>الكمية</th><th>السعر</th><th>الخصم</th><th>الضريبة</th><th>الإجمالي</th></tr>@foreach($invoice->items as $item)<tr><td>{{ $item->description }}</td><td>{{ $item->quantity }}</td><td>{{ $item->unit_price }}</td><td>{{ $item->discount_amount }}</td><td>{{ $item->tax_amount }}</td><td>{{ $item->line_total }}</td></tr>@endforeach</table><table class="table totals"><tr><th>المجموع</th><td>{{ $invoice->subtotal }}</td></tr><tr><th>الخصم</th><td>{{ $invoice->discount_total }}</td></tr><tr><th>الضريبة</th><td>{{ $invoice->tax_total }}</td></tr><tr><th>الإجمالي</th><td>{{ $invoice->grand_total }} {{ $invoice->currency }}</td></tr></table></div></body></html>
